/**
 * @summary Upload a document
 */
export const getUploadDocumentUrl = () => {
  return `/api/documents/upload`;
};

export const uploadDocument = async (
  uploadDocumentBody: UploadDocumentBody,
  options?: RequestInit,
): Promise<Document> => {
  const formData = new FormData();
  formData.append(`file`, uploadDocumentBody.file);
  formData.append(`supplierId`, uploadDocumentBody.supplierId.toString());
  if (uploadDocumentBody.contractId !== undefined) {
    formData.append(`contractId`, uploadDocumentBody.contractId.toString());
  }
  formData.append(`documentType`, uploadDocumentBody.documentType);
  if (uploadDocumentBody.description !== undefined) {
    formData.append(`description`, uploadDocumentBody.description);
  }

  return customFetch<Document>(getUploadDocumentUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

